                writer.WriteBoolean("is_template", projectResponse.IsTemplateOption.Value!.Value);

            if (projectResponse.TemplateSourceIdOption.IsSet)
                if (projectResponse.TemplateSourceIdOption.Value != null)
                    writer.WriteNumber("template_source_id", projectResponse.TemplateSourceIdOption.Value!.Value);
                else
                    writer.WriteNull("template_source_id");

            if (projectResponse.ParentIdOption.IsSet)
                if (projectResponse.ParentIdOption.Value != null)
                    writer.WriteNumber("parent_id", projectResponse.ParentIdOption.Value!.Value);
                else
                    writer.WriteNull("parent_id");

            if (projectResponse.ParentNameOption.IsSet)
                if (projectResponse.ParentNameOption.Value != null)
                    writer.WriteString("parent_name", projectResponse.ParentName);
                else
                    writer.WriteNull("parent_name");

            if (projectResponse.ChildrenOption.IsSet)
            {
                writer.WritePropertyName("children");
                JsonSerializer.Serialize(writer, projectResponse.Children, jsonSerializerOptions);
            }
            if (projectResponse.StatsOption.IsSet)
                if (projectResponse.StatsOption.Value != null)
                {
                    writer.WritePropertyName("stats");
                    JsonSerializer.Serialize(writer, projectResponse.Stats, jsonSerializerOptions);
                }
                else
                    writer.WriteNull("stats");
            if (projectResponse.UrlOption.IsSet)
                if (projectResponse.UrlOption.Value != null)
                    writer.WriteString("url", projectResponse.Url);
                else
                    writer.WriteNull("url");

            if (projectResponse.CoverImageFilenameOption.IsSet)
                if (projectResponse.CoverImageFilenameOption.Value != null)
                    writer.WriteString("cover_image_filename", projectResponse.CoverImageFilename);
                else
                    writer.WriteNull("cover_image_filename");
        }
    }
